1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	export const nextGeneration = (cells: Cell[]): Cell[] => {
12	  const alive = new Set(cells.map(cellKey));
13	  const candidates = new Map<string, Cell>();
14	  const counts = new Map<string, number>();
15	
16	  for (const [x, y] of cells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: Cell = [x + dx, y + dy];
19	      const k = cellKey(neighbor);
20	      candidates.set(k, neighbor);
21	      counts.set(k, (counts.get(k) ?? 0) + 1);
22	    }
23	  }
24	
25	  const livesNextGen = (k: string, n: number): boolean =>
26	    n === 3 || (n === 2 && alive.has(k));
27	
28	  return [...candidates]
29	    .filter(([k, _]) => livesNextGen(k, counts.get(k) ?? 0))
30	    .map(([_, cell]) => cell);
31	};
