1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2 square) stable across generations", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should transform a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
26	    // Pattern: ### / .#. / ###
27	    // Center (1,1) has 6 live neighbors → dies
28	    const input: [number, number][] = [
29	      [0, 0], [1, 0], [2, 0],
30	      [1, 1],
31	      [0, 2], [1, 2], [2, 2],
32	    ];
33	    const result = nextGeneration(input);
34	    // Center cell (1,1) should NOT be in result
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
38	    // L-shape: (0,0), (1,0), (0,1). Dead cell (1,1) has 3 live neighbors → born
39	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
40	    const result = nextGeneration(input);
41	    expect(result).toContainEqual([1, 1]);
42	  });
43	  it.todo("should handle negative coordinates correctly");
44	});
