export const nextGeneration = (cells: Cell[]): Cell[] => {
  const alive = new Set(cells.map(cellKey));
  const neighborTallies = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      const entry = neighborTallies.get(k);
      if (entry) entry.count += 1;
      else neighborTallies.set(k, { cell: neighbor, count: 1 });
    }
  }

  const livesNextGen = (k: string, n: number): boolean =>
    n === 3 || (n === 2 && alive.has(k));

  return [...neighborTallies]
    .filter(([k, { count }]) => livesNextGen(k, count))
    .map(([_, { cell }]) => cell);
};

